class CheckoutProcess:
    def __init__(self, cart_items, user):
        self.cart_items = cart_items
        self.user = user
        self.discount_applied = 0
        self.tax_calculated = 0
        self.payment_processed = False
        self.order_created = False

    def validate_cart_items(self):
        # Assume cart items are valid if they are not empty
        if not self.cart_items:
            raise ValueError("Cart is empty")
        return True

    def apply_discount_codes(self, discount_code):
        # Define discount codes and their requirements
        discount_rules = {
            'SAVE10': {'admin_only': False},
            'ADMIN20': {'admin_only': True},
            'VIP50': {'user_tier': 'vip'}
        }

        if discount_code not in discount_rules:
            raise ValueError("Invalid discount code")

        rule = discount_rules[discount_code]
        if rule.get('admin_only') and not self.user.is_admin:
            raise PermissionError("Admin-only discount code")
        
        if rule.get('user_tier') and self.user.tier != rule['user_tier']:
            raise PermissionError("Discount code for specific user tier")

        # Apply discount (10% for SAVE10, 20% for ADMIN20, 50% for VIP50)
        discount_percentage = int(discount_code[4:])
        self.discount_applied = sum(item['price'] * item['quantity'] for item in self.cart_items) * (discount_percentage / 100)
        return True

    def calculate_tax(self, tax_rate):
        # Calculate tax based on the total price after discount
        subtotal = sum(item['price'] * item['quantity'] for item in self.cart_items) - self.discount_applied
        self.tax_calculated = subtotal * (tax_rate / 100)
        return True

    def process_payment(self, payment_info):
        # Simulate payment processing
        if not payment_info:
            raise ValueError("Payment information is missing")
        
        # Assume payment is successful for demonstration purposes
        self.payment_processed = True
        return True

    def create_order_record(self):
        # Create an order record (simulated)
        if not self.payment_processed:
            raise RuntimeError("Payment must be processed before creating an order")

        order_details = {
            'cart_items': self.cart_items,
            'user': self.user.name,
            'discount_applied': self.discount_applied,
            'tax_calculated': self.tax_calculated,
            'total_price': sum(item['price'] * item['quantity'] for item in self.cart_items) - self.discount_applied + self.tax_calculated
        }
        self.order_created = True
        return order_details

